import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './studentdashboard.css';

function StudentDashboard() {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [projectData, setProjectData] = useState({
    title: '',
    description: '',
    objectives: '',
    timeline: '',
    resources: '',
    mentorId: '',
    status: 'pending'
  });
  const [studentData, setStudentData] = useState(null);
  const [mentorData, setMentorData] = useState(null);
  const [meetings, setMeetings] = useState([]);
  const [reports, setReports] = useState([]);
  const [loading, setLoading] = useState(true);
  const [availableMentors, setAvailableMentors] = useState([]);
  const [selectedMentor, setSelectedMentor] = useState(null);
  const [requestStatus, setRequestStatus] = useState('');
  const [mentorSlots, setMentorSlots] = useState([]);
  const [selectedMentorForSlots, setSelectedMentorForSlots] = useState(null);

  // Upload state
  const [uploadType, setUploadType] = useState('report');
  const [uploadTitle, setUploadTitle] = useState('');
  const [uploadDescription, setUploadDescription] = useState('');
  const [uploadFile, setUploadFile] = useState(null);
  const [uploadStatus, setUploadStatus] = useState('');

  const [showProjectForm, setShowProjectForm] = useState(false);
  const [projectFormData, setProjectFormData] = useState({
    title: '',
    description: '',
    objectives: '',
    timeline: '',
    resources: ''
  });

  // Fetch user data on component mount
  useEffect(() => {
    const fetchUserData = async () => {
      try {
        const user = JSON.parse(localStorage.getItem('user'));
        if (!user) {
          navigate('/');
          return;
        }

        // Fetch student's data from backend
        const token = localStorage.getItem('token');
        const res = await axios.get('http://localhost:5050/api/students/me', {
          headers: { Authorization: `Bearer ${token}` }
        });
        setStudentData(res.data);

        // Fetch student's project data if it exists
        const projectsQuery = query(
          collection(db, "projects"),
          where("studentId", "==", user.uid)
        );
        const projectsSnapshot = await getDocs(projectsQuery);
        if (!projectsSnapshot.empty) {
          const projectDoc = projectsSnapshot.docs[0];
          setProjectData({ id: projectDoc.id, ...projectDoc.data() });

          // If project has mentor, fetch mentor details
          const projectData = projectDoc.data();
          if (projectData.mentorId) {
            const mentorDoc = await getDoc(doc(db, "users", projectData.mentorId));
            if (mentorDoc.exists()) {
              setMentorData(mentorDoc.data());
            }
          }
        }

        // Fetch student's meetings
        const meetingsQuery = query(
          collection(db, "meetings"),
          where("studentId", "==", user.uid)
        );
        const meetingsSnapshot = await getDocs(meetingsQuery);
        const meetingsData = meetingsSnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        }));
        setMeetings(meetingsData);

        // Fetch student's reports
        const reportsQuery = query(
          collection(db, "reports"),
          where("studentId", "==", user.uid)
        );
        const reportsSnapshot = await getDocs(reportsQuery);
        const reportsData = reportsSnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        }));
        setReports(reportsData);
      } catch (error) {
        console.error("Error fetching student data:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchUserData();
  }, [navigate]);

  // Fetch available mentors
  useEffect(() => {
    const fetchAvailableMentors = async () => {
      try {
        const mentorsQuery = query(
          collection(db, "users"),
          where("role", "==", "mentor")
        );

        const mentorsSnapshot = await getDocs(mentorsQuery);
        const mentors = mentorsSnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        })).filter(mentor => {
          // Include mentors that either don't have a status field or have status as "active"
          return !mentor.status || mentor.status === "active";
        });

        setAvailableMentors(mentors);
      } catch (error) {
        console.error("Error fetching mentors:", error);
      }
    };

    fetchAvailableMentors();
  }, []);

  // when availableMentors and studentData are ready, auto-select assigned mentor
  useEffect(() => {
    if (!studentData || availableMentors.length === 0) return;
    if (studentData.mentorId) {
      const m = availableMentors.find(x => x.id === studentData.mentorId);
      if (m) setSelectedMentorForSlots(m);
    }
  }, [studentData, availableMentors]);

  // realtime listen to selected mentor slots
  useEffect(() => {
    if (!selectedMentorForSlots) { setMentorSlots([]); return; }
    const q2 = query(collection(db, 'availability'), where('mentorId', '==', selectedMentorForSlots.id));
    const unsub = onSnapshot(q2, (snap) => {
      setMentorSlots(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    });
    return unsub;
  }, [selectedMentorForSlots]);

  // add state for my requests
  const [myRequests, setMyRequests] = useState([]);

  // subscribe to own mentor requests
  useEffect(() => {
    const user = auth.currentUser;
    if (!user) return;
    const rq = query(collection(db, 'mentorRequests'), where('studentId', '==', user.uid));
    const unsub = onSnapshot(rq, (snap) => {
      setMyRequests(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    });
    return unsub;
  }, []);

  const handleLogout = async () => {
    try {
      await signOut(auth);
      navigate('/');
    } catch (error) {
      console.error("Error signing out:", error);
    }
  };

  const handleFileChange = (e) => {
    if (e.target.files[0]) {
      setUploadFile(e.target.files[0]);
    }
  };

  const handleUpload = async (e) => {
    e.preventDefault();

    if (!uploadFile) {
      setUploadStatus('Please select a file to upload');
      return;
    }

    try {
      setUploadStatus('Uploading...');
      const user = auth.currentUser;

      // Upload file to Firebase Storage
      const storageRef = ref(storage, `documents/${user.uid}/${Date.now()}_${uploadFile.name}`);
      await uploadBytes(storageRef, uploadFile);
      const fileUrl = await getDownloadURL(storageRef);

      // Add document record to Firestore
      await addDoc(collection(db, "reports"), {
        studentId: user.uid,
        title: uploadTitle,
        description: uploadDescription,
        type: uploadType,
        fileUrl: fileUrl,
        status: 'pending',
        submittedAt: serverTimestamp()
      });

      // Reset form
      setUploadTitle('');
      setUploadDescription('');
      setUploadFile(null);
      setUploadStatus('Document uploaded successfully!');

      // Refresh reports list
      const reportsQuery = query(
        collection(db, "reports"),
        where("studentId", "==", user.uid)
      );
      const reportsSnapshot = await getDocs(reportsQuery);
      const reportsData = reportsSnapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));
      reportsData.sort((a, b) => {
        const dateA = a.submittedAt?.toDate() || new Date(0);
        const dateB = b.submittedAt?.toDate() || new Date(0);
        return dateB - dateA;
      });
      setReports(reportsData);
    } catch (error) {
      console.error("Error uploading document:", error);
      setUploadStatus('Error uploading document. Please try again.');
    }
  };

  const handleProjectSubmit = async (e) => {
    e.preventDefault();
    if (!projectData.title || !projectData.description || !projectData.mentorId) {
        alert('Please fill in all required fields and select a mentor');
        return;
    }

    try {
        const user = auth.currentUser;
        // Check if a project already exists for this student
        const existingQ = query(collection(db, 'projects'), where('studentId', '==', user.uid));
        const existingSnap = await getDocs(existingQ);
        if (!existingSnap.empty) {
          // Update the first existing project
          const existingDoc = existingSnap.docs[0];
          await updateDoc(doc(db, 'projects', existingDoc.id), {
            title: projectData.title,
            description: projectData.description,
            objectives: projectData.objectives || '',
            timeline: projectData.timeline || '',
            resources: projectData.resources || '',
            mentorId: projectData.mentorId,
            lastUpdated: serverTimestamp(),
          });
          setProjectData({ id: existingDoc.id, ...existingDoc.data(), ...projectData });
          alert('Project updated successfully!');
          // Sync project title in mentor's assignedStudents if student already has a mentor
          if (studentData?.mentorId) {
            const mRef = doc(db, 'users', studentData.mentorId);
            const mSnap = await getDoc(mRef);
            if (mSnap.exists()) {
              const mData = mSnap.data();
              const list = Array.isArray(mData.assignedStudents) ? mData.assignedStudents : [];
              const updated = list.map(s => s.id === user.uid ? { ...s, projectTitle: projectData.title } : s);
              if (JSON.stringify(updated) !== JSON.stringify(list)) {
                await updateDoc(mRef, { assignedStudents: updated });
              }
            }
          }
        } else {
          // Create new project
          const projectRef = doc(collection(db, 'projects'));
          await setDoc(projectRef, {
              ...projectData,
              studentId: user.uid,
              studentName: user.displayName,
              studentEmail: user.email,
              createdAt: serverTimestamp(),
              lastUpdated: serverTimestamp()
          });
          setProjectData({
              title: '',
              description: '',
              objectives: '',
              timeline: '',
              resources: '',
              mentorId: '',
              status: 'pending'
          });
          alert('Project submitted successfully!');
        }
    } catch (error) {
        console.error('Error submitting project:', error);
        alert('Error submitting project. Please try again.');
    }
  };

  const handleProjectFormChange = (e) => {
    const { name, value } = e.target;
    setProjectFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleMentorRequest = async (mentorId) => {
    try {
      // must have a project first
      if (!projectData?.id) {
        alert('Please submit your project first. Redirecting to Project tab...');
        setActiveTab('project');
        return;
      }

      setRequestStatus('Sending request...');
      await addDoc(collection(db, 'mentorRequests'), {
        studentId: auth.currentUser.uid,
        mentorId,
        status: 'pending',
        createdAt: serverTimestamp(),
        studentName: studentData?.name || 'Student',
        studentEmail: auth.currentUser.email,
        projectId: projectData.id,
        projectTitle: projectData.title || ''
      });
      setRequestStatus('Request sent successfully!');
      // go to project tab so the student stays in context
      setActiveTab('project');
      setTimeout(() => setRequestStatus(''), 2500);
    } catch (error) {
      console.error('Error sending mentor request:', error);
      setRequestStatus('Failed to send request. Please try again.');
    }
  };

  const handleDeleteProject = async () => {
    try {
      const user = auth.currentUser;
      if (!user) {
        alert('Please log in to delete the project');
        return;
      }

      if (!projectData?.id) {
        alert('No project to delete');
        return;
      }

      // Get the mentor's ID before deleting the project
      const mentorId = projectData.mentorId;

      // Delete the project document
      await deleteDoc(doc(db, "projects", projectData.id));

      // If there was a mentor assigned, update their available slots and assigned students
      if (mentorId) {
        const mentorRef = doc(db, "users", mentorId);
        const mentorDoc = await getDoc(mentorRef);

        if (mentorDoc.exists()) {
          const mentorData = mentorDoc.data();
          const currentStudents = mentorData.assignedStudents || [];

          // Remove the student from the assigned students list
          const updatedStudents = currentStudents.filter(
            student => student.id !== user.uid
          );

          // Update mentor's document with new available slots and assigned students
          await updateDoc(mentorRef, {
            availableSlots: increment(1),
            assignedStudents: updatedStudents
          });
        }
      }

      // Clear the project data from state
      setProjectData({
        title: '',
        description: '',
        objectives: '',
        timeline: '',
        resources: '',
        mentorId: '',
        status: 'pending'
      });

      // Show success message
      alert('Project deleted successfully');
    } catch (error) {
      console.error('Error deleting project:', error);
      alert('Error deleting project. Please try again.');
    }
  };

  if (loading) {
    return <div className="loading">Loading...</div>;
  }

  return (
    <div className="student-dashboard">
      <div className="dashboard-header">
        <h1>Student Dashboard</h1>
        <button onClick={handleLogout}>Logout</button>
      </div>

      <div className="tabs">
        <button 
          className={activeTab === 'dashboard' ? 'active' : ''}
          onClick={() => setActiveTab('dashboard')}
        >
          Dashboard
        </button>
        <button 
          className={activeTab === 'project' ? 'active' : ''}
          onClick={() => setActiveTab('project')}
        >
          Project
        </button>
        <button 
          className={activeTab === 'mentors' ? 'active' : ''}
          onClick={() => setActiveTab('mentors')}
        >
          Find Mentors
        </button>
        <button 
          className={activeTab === 'meetings' ? 'active' : ''}
          onClick={() => setActiveTab('meetings')}
        >
          Meetings
        </button>
        <button 
          className={activeTab === 'reports' ? 'active' : ''}
          onClick={() => setActiveTab('reports')}
        >
          Reports
        </button>
      </div>

      <div className="main-content">
        {activeTab === 'dashboard' && (
          <div className="dashboard-section">
            <h2>Welcome, {studentData?.name || 'Student'}</h2>
            <div className="stats">
              <div className="stat-card">
                <h3>Project Status</h3>
                <p>{projectData?.status || 'Not submitted'}</p>
              </div>
              <div className="stat-card">
                <h3>Assigned Mentor</h3>
                <p>{mentorData?.name || 'Not assigned'}</p>
              </div>
              <div className="stat-card">
                <h3>Upcoming Meetings</h3>
                <p>{meetings.filter(m => new Date(m.date) > new Date()).length}</p>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'project' && (
          <div className="project-section">
            <h2>Project Submission</h2>
            {!projectData?.id ? (
              <div className="project-form">
                <h3>Submit New Project</h3>
                <form onSubmit={handleProjectSubmit}>
                  <div className="form-group">
                    <label>Project Title *</label>
                    <input
                      type="text"
                      value={projectData.title}
                      onChange={(e) => setProjectData({ ...projectData, title: e.target.value })}
                      required
                    />
                  </div>
                  <div className="form-group">
                    <label>Select Mentor *</label>
                    <select
                      value={projectData.mentorId}
                      onChange={(e) => setProjectData({ ...projectData, mentorId: e.target.value })}
                      required
                    >
                      <option value="">Select a mentor</option>
                      {availableMentors.map(mentor => (
                        <option key={mentor.id} value={mentor.id}>
                          {mentor.name} - {mentor.institution}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Project Description *</label>
                    <textarea
                      value={projectData.description}
                      onChange={(e) => setProjectData({ ...projectData, description: e.target.value })}
                      required
                    />
                  </div>
                  <div className="form-group">
                    <label>Project Objectives</label>
                    <textarea
                      value={projectData.objectives}
                      onChange={(e) => setProjectData({ ...projectData, objectives: e.target.value })}
                    />
                  </div>
                  <div className="form-group">
                    <label>Project Timeline</label>
                    <textarea
                      value={projectData.timeline}
                      onChange={(e) => setProjectData({ ...projectData, timeline: e.target.value })}
                    />
                  </div>
                  <div className="form-group">
                    <label>Required Resources</label>
                    <textarea
                      value={projectData.resources}
                      onChange={(e) => setProjectData({ ...projectData, resources: e.target.value })}
                    />
                  </div>
                  <div className="form-actions">
                    <button type="submit" className="submit-btn">Submit Project</button>
                    <button type="button" className="cancel-btn" onClick={() => setProjectData({ ...projectData, title: '' })}>Cancel</button>
                  </div>
                </form>
              </div>
            ) : (
              <div className="project-details">
                <div className="project-header">
                  <h3>{projectData.title}</h3>
                  <button 
                    className="delete-project-btn"
                    onClick={handleDeleteProject}
                  >
                    Delete Project
                  </button>
                </div>
                <div className="project-info">
                  <p><strong>Status:</strong> {projectData.status}</p>
                  <p><strong>Description:</strong> {projectData.description}</p>
                  {projectData.objectives && (
                    <p><strong>Objectives:</strong> {projectData.objectives}</p>
                  )}
                  {projectData.timeline && (
                    <p><strong>Timeline:</strong> {projectData.timeline}</p>
                  )}
                  {projectData.resources && (
                    <p><strong>Resources:</strong> {projectData.resources}</p>
                  )}
                </div>
              </div>
            )}
          </div>
        )}

        {activeTab === 'mentors' && (
          <div className="mentors-section">
            <h2>Available Mentors</h2>
            {availableMentors.length === 0 ? (
              <p>No mentors available at the moment.</p>
            ) : (
              <div className="mentor-cards">
                {availableMentors.map(mentor => (
                  <div className="mentor-card" key={mentor.id}>
                    <h3>{mentor.name}</h3>
                    <p><strong>Email:</strong> {mentor.email}</p>
                    <p><strong>Institution:</strong> {mentor.institution}</p>
                    {mentor.specialties && (
                      <div className="mentor-specialties">
                        <strong>Specialties:</strong>
                        <div className="specialties-list">
                          {mentor.specialties.map((specialty, index) => (
                            <span key={index} className="specialty-tag">
                              {specialty}
                            </span>
                          ))}
                        </div>
                      </div>
                    )}
                    <button 
                      className="request-mentor-btn"
                      onClick={() => handleMentorRequest(mentor.id)}
                      disabled={Boolean(studentData?.mentorId)}
                    >
                      {Boolean(studentData?.mentorId) ? 'Mentor Assigned' : 'Request Mentor'}
                    </button>
                    {requestStatus && <p className="request-status">{requestStatus}</p>}
                  </div>
                ))}
              </div>
            )}
            <div className="my-requests" style={{marginTop:20}}>
              <h3>My Requests</h3>
              {myRequests.length === 0 ? <p>No requests yet.</p> : (
                <ul>
                  {myRequests.map(r => (
                    <li key={r.id}>
                      To: {availableMentors.find(m=>m.id===r.mentorId)?.name || r.mentorId} - {r.status}
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        )}

        {activeTab === 'meetings' && (
          <div className="meetings-section">
            <h2>Meetings</h2>
            {studentData?.mentorId ? (
              <>
                <p><strong>Assigned Mentor:</strong> {mentorData?.name || 'Loading...'}</p>
                <div style={{ margin: '10px 0' }}>
                  <label htmlFor="mentorSlotSelect">Mentor:</label>{' '}
                  <select id="mentorSlotSelect" value={selectedMentorForSlots?.id || ''} disabled>
                    <option value={selectedMentorForSlots?.id || ''}>{mentorData?.name || 'Assigned Mentor'}</option>
                  </select>
                </div>
                <div className="meetings-list">
                  {mentorSlots.length === 0 ? (
                    <p>No slots published by your mentor yet.</p>
                  ) : (
                    mentorSlots.map(slot => (
                      <div className="meeting-card" key={slot.id}>
                        <h3>{slot.day}</h3>
                        <p><strong>Time:</strong> {slot.startTime} - {slot.endTime}</p>
                        <p><strong>Status:</strong> {slot.status}</p>
                        {slot.status === 'free' ? (
                          <button
                            className="request-mentor-btn"
                            onClick={async () => {
                              try {
                                await updateDoc(doc(db, 'availability', slot.id), {
                                  status: 'booked',
                                  studentId: auth.currentUser.uid
                                });
                                alert('Slot booked');
                              } catch (e) {
                                console.error(e);
                                alert('Failed to book slot');
                              }
                            }}
                          >
                            Book Slot
                          </button>
                        ) : (
                          <span style={{ color: slot.studentId === auth.currentUser.uid ? '#4caf50' : '#999' }}>
                            {slot.studentId === auth.currentUser.uid ? 'Booked by you' : 'Booked'}
                          </span>
                        )}
                      </div>
                    ))
                  )}
                </div>
              </>
            ) : (
              <>
                <p>No mentor assigned. Please request a mentor in the "Find Mentors" tab to schedule meetings.</p>
                <div>
                  <label htmlFor="mentorSlotSelect">Preview Slots by Mentor:</label>{' '}
                  <select id="mentorSlotSelect" value={selectedMentorForSlots?.id || ''} onChange={e => {
                    const mid = e.target.value;
                    setSelectedMentorForSlots(availableMentors.find(m => m.id === mid) || null);
                  }}>
                    <option value="">Choose Mentor</option>
                    {availableMentors.map(m => <option value={m.id} key={m.id}>{m.name}</option>)}
                  </select>
                  {selectedMentorForSlots && (
                    <div className="meetings-list" style={{ marginTop: 10 }}>
                      {mentorSlots.length === 0 ? <p>No slots for this mentor yet.</p> : mentorSlots.map(slot => (
                        <div className="meeting-card" key={slot.id}>
                          <h3>{slot.day}</h3>
                          <p><strong>Time:</strong> {slot.startTime} - {slot.endTime}</p>
                          <p><strong>Status:</strong> {slot.status}</p>
                          <span style={{ color: '#999' }}>Request a mentor to book</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </>
            )}
          </div>
        )}

        {activeTab === 'reports' && (
          <div className="reports-section">
            <h2>Reports</h2>
            {reports.length === 0 ? (
              <p>No reports submitted yet.</p>
            ) : (
              <div className="reports-list">
                {reports.map(report => (
                  <div className="report-card" key={report.id}>
                    <h3>{report.title}</h3>
                    <p><strong>Date:</strong> {new Date(report.date).toLocaleDateString()}</p>
                    <p><strong>Status:</strong> {report.status}</p>
                    {report.feedback && (
                      <p><strong>Feedback:</strong> {report.feedback}</p>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default StudentDashboard;
